2103 |     function resolvePath(base, relative) {
2104 |         const stack = base.split('/');
2105 |         stack.pop(); 
2106 |         const parts = relative.split('/');
2107 |         for (let i = 0; i < parts.length; i++) {
2108 |             if (parts[i] === '.') continue;
2109 |             if (parts[i] === '..') stack.pop();
2110 |             else stack.push(parts[i]);
2111 |         }
2112 |         return stack.join('/');
2113 |     }
