5425 |     function formatBytes(bytes) {
5426 |         if (!bytes) return '0 B';
5427 |         const k = 1024;
5428 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5429 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5430 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5431 |     }
