5433 |     function timeAgo(dateString) {
5434 |         const date = new Date(dateString);
5435 |         const now = new Date();
5436 |         const seconds = Math.floor((now - date) / 1000);
5437 |         if (seconds < 10) return 'just now';
5438 |         if (seconds < 60) return seconds + 's ago';
5439 |         const minutes = Math.floor(seconds / 60);
5440 |         if (minutes < 60) return minutes + 'm ago';
5441 |         const hours = Math.floor(minutes / 60);
5442 |         if (hours < 24) return hours + 'h ago';
5443 |         return date.toLocaleDateString();
5444 |     }
