5672 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5673 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5674 |         
5675 |         const navItems = document.querySelectorAll('.nav-item');
5676 |         switchTab(tabId, navItems[navIndex]);
5677 | 
5678 |         const scrollContainer = document.querySelector('.main-view');
5679 |         let retryCount = 0;
5680 |         const MAX_RETRIES = 5;
5681 | 
5682 |         const attemptNavigation = async () => {
5683 |             const element = document.querySelector(selector);
5684 |             
5685 |             if (element) {
5686 |                 console.log("[DeepJump] Element found. Scrolling...");
5687 |                 
5688 |                 // Wait for any tab transition animations
5689 |                 await new Promise(r => setTimeout(r, 300));
5690 | 
5691 |                 let offsetTop = 0;
5692 |                 let curr = element;
5693 |                 while (curr && curr !== scrollContainer) {
5694 |                     offsetTop += curr.offsetTop;
5695 |                     curr = curr.offsetParent;
5696 |                 }
5697 | 
5698 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5699 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5700 | 
5701 |                 // Visual Highlight
5702 |                 element.style.transition = 'all 0.5s ease';
5703 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5704 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5705 |                 setTimeout(() => {
