5707 |                     element.style.boxShadow = '';
5708 |                 }, 3000);
5709 |                 
5710 |                 console.groupEnd();
5711 |                 return true;
5712 |             }
5713 | 
5714 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5715 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5716 |                 retryCount++;
5717 |                 showGlobalToast("🔍 Searching deeper...");
5718 |                 
5719 |                 await loadMoreFn(); 
5720 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5721 |                 return attemptNavigation();
5722 |             }
5723 | 
5724 |             console.error("[DeepJump] Failed: Element not found after retries.");
5725 |             showGlobalToast("Entry not found in recent history.", true);
5726 |             console.groupEnd();
5727 |             return false;
5728 |         };
5729 | 
5730 |         setTimeout(attemptNavigation, 100);
