7293 |         diffLeft.setValue("Loading...", -1);
7294 |         diffRight.setValue("Loading...", -1);
7295 | 
7296 |         try {
7297 |             let leftContent = "", rightContent = "";
7298 | 
7299 |             if (forcedLeft !== null && forcedRight !== null) {
7300 |                 leftContent = forcedLeft;
7301 |                 rightContent = forcedRight;
7302 |             } else {
7303 |                 const rightRef = data.commit_sha || 'HEAD';
7304 |                 const leftRef = rightRef + '^';
