7309 |                         body: apiBody({ action: 'preview_file', file_path: data.file, ref_sha: ref })
7310 |                     });
7311 |                     const d = await res.json();
7312 |                     return d.content ? b64DecodeUnicode(d.content) : '';
7313 |                 };
7314 | 
7315 |                 const results = await Promise.all([
7316 |                     fetchFile(leftRef).catch(() => ""),
7317 |                     fetchFile(rightRef).catch(() => "")
7318 |                 ]);
7319 |                 leftContent = results[0];
7320 |                 rightContent = results[1];
7321 |             }
7322 | 
7323 |             let mode = "ace/mode/text";
7324 |             if (data.file.endsWith('.js')) mode = "ace/mode/javascript";
7325 |             else if (data.file.endsWith('.html')) mode = "ace/mode/html";
7326 |             else if (data.file.endsWith('.css')) mode = "ace/mode/css";
7327 |             else if (data.file.endsWith('.json')) mode = "ace/mode/json";
7328 |             else if (data.file.endsWith('.md')) mode = "ace/mode/markdown";
7329 |             
7330 |             diffLeft.session.setMode(mode);
