7335 | 
7336 |             const Range = ace.require('ace/range').Range;
7337 | 
7338 |             // Helper to get Range from String Index
7339 |             const getRangeFromText = (session, searchText) => {
7340 |                 const fullText = session.getValue();
7341 |                 // 1. Try Exact Match
7342 |                 let startIdx = fullText.indexOf(searchText);
7343 |                 
7344 |                 // 2. Try Robust Match (Ignoring Line Endings differences)
7345 |                 if (startIdx === -1) {
7346 |                     const clean = (s) => s.replace(/\r\n/g, '\n').trim();
7347 |                     startIdx = clean(fullText).indexOf(clean(searchText));
