8465 |     function extractTableNames(sql) {
8466 |         if (!sql) return [];
8467 |         const tables = [];
8468 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
8469 |         
8470 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
8471 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
8472 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
8473 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
8474 | 
8475 |         let match;
8476 |         while ((match = fromRegex.exec(sql)) !== null) {
8477 |             const name = match[1];
8478 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8479 |                 tables.push(name);
8480 |             }
8481 |         }
8482 |         
8483 |         while ((match = metaRegex.exec(sql)) !== null) {
8484 |             const name = match[1];
8485 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8486 |                 tables.push(name);
8487 |             }
8488 |         }
8489 | 
8490 |         return tables;
8491 |     }
8492 | 
8493 |     function convertToCSV(resultObj) {
8494 |         const data = resultObj.data || [];
8495 |         if (!data.length) return '';
8496 |         
8497 |         const tables = extractTableNames(resultObj.sql);
8498 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
8499 | 
8500 |         const headers = Object.keys(data[0]);
8501 |         const rows = data.map(row => 
8502 |             headers.map(header => {
8503 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
8504 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
8505 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
8506 |             }).join(',')
8507 |         );
8508 |         return metaHeader + [headers.join(','), ...rows].join('\n');
8509 |     }
